ixs_node *ixs_rat(ixs_ctx *ctx, int64_t p, int64_t q) {
  if (q == 0)
    return ctx_err(ctx, "ixs_rat: denominator is zero");
  int64_t rp, rq;
  if (!ixs_rat_normalize(p, q, &rp, &rq))
    return ctx_err(ctx, "ixs_rat: rational overflow");
  return ixs_node_rat(ctx, rp, rq);
}

